import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { format, subMonths, startOfMonth, endOfMonth } from "date-fns";
import {
  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer,
  CartesianGrid, BarChart, Bar, Cell,
} from "recharts";
import {
  LayoutDashboard, Users, CreditCard, FileText, MessageSquare,
  Settings, Shield, CheckCircle, XCircle, Search, Menu,
  LogOut, Loader2, X, Receipt, FileCheck, ChevronRight,
  TrendingUp, TrendingDown, Minus, ArrowUpRight,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

// ─── Helpers ──────────────────────────────────────────────────────────────────
const KES = (n: number) =>
  n >= 1_000_000
    ? `KES ${(n / 1_000_000).toFixed(1)}M`
    : n >= 1_000
    ? `KES ${(n / 1_000).toFixed(1)}K`
    : `KES ${Math.round(n).toLocaleString()}`;

const fmt = (n: number) =>
  n >= 1_000_000 ? `${(n / 1_000_000).toFixed(1)}M`
  : n >= 1_000   ? `${(n / 1_000).toFixed(1)}K`
  : String(n);

type Section = "overview" | "users" | "billing" | "documents" | "support" | "settings";

const planChip = (plan: string | null) => cn(
  "text-[10px] font-semibold px-2 py-0.5 rounded-full",
  plan === "pro"          ? "bg-emerald-500/20 text-emerald-400"
  : plan === "enterprise" ? "bg-violet-500/20  text-violet-400"
  : "bg-white/[0.07] text-white/30"
);

const statusChip = (s: string) => cn(
  "text-[10px] font-semibold px-2 py-0.5 rounded-full",
  s === "paid" || s === "signed" || s === "completed" || s === "success"
    ? "bg-emerald-500/20 text-emerald-400"
  : s === "overdue" || s === "cancelled" || s === "failed"
    ? "bg-red-500/20 text-red-400"
  : s === "sent"
    ? "bg-blue-500/20 text-blue-400"
  : "bg-amber-500/20 text-amber-400"
);

// ─── Shared UI ────────────────────────────────────────────────────────────────
const Av = ({ url, name, size = "9" }: { url?: string | null; name?: string | null; size?: string }) => (
  <div className={`w-${size} h-${size} rounded-full bg-white/10 flex items-center justify-center text-xs text-white/60 flex-shrink-0 overflow-hidden ring-1 ring-white/5`}>
    {url
      ? <img src={url} alt="" className="w-full h-full object-cover" />
      : <span className="font-semibold">{(name?.[0] || "?").toUpperCase()}</span>}
  </div>
);

const Spin = () => (
  <div className="flex items-center justify-center h-64">
    <Loader2 className="w-5 h-5 text-bronze animate-spin" />
  </div>
);

const Trend = ({ pct }: { pct: number | null }) => {
  if (pct === null) return <span className="text-[10px] text-white/20 font-medium">—</span>;
  if (pct === 0)    return (
    <span className="flex items-center gap-0.5 text-[10px] text-white/30 font-semibold">
      <Minus className="w-3 h-3" /> 0%
    </span>
  );
  const up = pct > 0;
  return (
    <span className={cn("flex items-center gap-0.5 text-[10px] font-semibold",
      up ? "text-emerald-400" : "text-red-400")}>
      {up ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}

content.content:
80	      {up ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
81	      {up ? "+" : ""}{pct}%
82	    </span>
83	  );
84	};
85	
86	// Custom tooltip shared across charts
87	const ChartTooltip = ({ active, payload, label, prefix = "" }: any) => {
88	  if (!active || !payload?.length) return null;
89	  return (
90	    <div className="bg-[#1c1c1c] border border-white/10 rounded-xl px-3 py-2 shadow-xl">
91	      <p className="text-xs text-white/40 mb-1">{label}</p>
92	      <p className="text-sm font-bold text-white">{prefix}{payload[0]?.value?.toLocaleString()}</p>
93	    </div>
94	  );
95	};
96	
97	// ─── Stat Card ────────────────────────────────────────────────────────────────
98	const StatCard = ({
99	  label, value, sub, trend, icon: Icon, accent, onClick,
100	}: {
101	  label: string; value: string; sub?: string; trend?: number | null;
102	  icon: React.ElementType; accent: string; onClick?: () => void;
103	}) => (
104	  <div onClick={onClick} className={cn("group relative bg-[#111111] border border-white/[0.06] rounded-2xl p-5 hover:border-white/[0.12] hover:bg-[#161616] transition-all duration-200 overflow-hidden", onClick && "cursor-pointer")}>
105	    {/* Subtle accent glow top-right */}
106	    <div className={cn("absolute -top-6 -right-6 w-20 h-20 rounded-full blur-2xl opacity-20", accent)} />
107	    <div className="relative flex items-start justify-between mb-3">
108	      <div className={cn("w-8 h-8 rounded-xl flex items-center justify-center", accent, "bg-opacity-15")}>
109	        <Icon className="w-4 h-4 text-white/70" />
110	      </div>
111	      {trend !== undefined && <Trend pct={trend ?? null} />}
112	    </div>
113	    <p className="text-2xl md:text-3xl font-bold text-white tabular-nums tracking-tight leading-none mb-1">{value}</p>
114	    <p className="text-xs text-white/40 font-medium">{label}</p>
115	    {sub && <p className="text-[11px] text-white/20 mt-1 truncate">{sub}</p>}
116	  </div>
117	);
118	
119	// ─── Overview ─────────────────────────────────────────────────────────────────
120	const OverviewSection = ({ onNavigate }: { onNavigate: (s: Section) => void }) => {
121	  const [data, setData] = useState<{
122	    total: number; free: number; pro: number; enterprise: number;
123	    invoices: number; contracts: number;
124	    mrr: number; arr: number;
125	    userTrend: number | null; mrrTrend: number | null;
126	    mrrChart: { month: string; mrr: number }[];
127	    userChart: { month: string; users: number }[];
128	    planChart: { plan: string; count: number; pct: number }[];
129	    recent: any[];
130	  } | null>(null);
131	
132	  useEffect(() => { load(); }, []);
133	
134	  const load = async () => {
135	    const [{ data: profiles }, { count: inv }, { count: con }] = await Promise.all([
136	      supabase.from("profiles")
137	        .select("id, display_name, handle, subscription_plan, created_at, avatar_url")
138	        .order("created_at", { ascending: false }),
139	      supabase.from("invoices").select("id", { count: "exact", head: true }),
140	      supabase.from("contracts").select("id", { count: "exact", head: true }),
141	    ]);
142	
143	    const p = profiles ?? [];
144	    const pro = p.filter(u => u.subscription_plan === "pro").length;
145	    const ent = p.filter(u => u.subscription_plan === "enterprise").length;
146	    const free = p.length - pro - ent;
147	    const mrr = pro * 1500 + ent * 5000;
148	    const arr = mrr * 12;
149	
150	    // Trends — compare vs last month
151	    const now = new Date();
152	    const thisMonthStart = startOfMonth(now).toISOString();
153	    const lastMonthStart = startOfMonth(subMonths(now, 1)).toISOString();
154	    const lastMonthEnd   = endOfMonth(subMonths(now, 1)).toISOString();
155	
156	    const thisMonthUsers = p.filter(u => u.created_at && u.created_at >= thisMonthStart).length;
157	    const lastMonthUsers = p.filter(u => u.created_at && u.created_at >= lastMonthStart && u.created_at <= lastMonthEnd).length;
158	    const userTrend = lastMonthUsers > 0 ? Math.round(((thisMonthUsers - lastMonthUsers) / lastMonthUsers) * 100) : null;
159	
160	    const prevPro = p.filter(u => u.subscription_plan === "pro" && u.created_at && u.created_at <= lastMonthEnd).length;
161	    const prevEnt = p.filter(u => u.subscription_plan === "enterprise" && u.created_at && u.created_at <= lastMonthEnd).length;
162	    const prevMrr = prevPro * 1500 + prevEnt * 5000;
163	    const mrrTrend = prevMrr > 0 ? Math.round(((mrr - prevMrr) / prevMrr) * 100) : null;
164	
165	    // MRR chart — cumulative by month (how MRR grew over time)
166	    const mrrChart = Array.from({ length: 6 }, (_, i) => {
167	      const d = subMonths(now, 5 - i);
168	      const end = endOfMonth(d).toISOString();
169	      const mPro = p.filter(u => u.subscription_plan === "pro" && u.created_at && u.created_at <= end).length;
170	      const mEnt = p.filter(u => u.subscription_plan === "enterprise" && u.created_at && u.created_at <= end).length;
171	      return { month: format(d, "MMM"), mrr: mPro * 1500 + mEnt * 5000 };
172	    });
173	
174	    // User growth chart — new signups per month
175	    const userChart = Array.from({ length: 6 }, (_, i) => {
176	      const d = subMonths(now, 5 - i);
177	      const s = startOfMonth(d).toISOString();
178	      const e = endOfMonth(d).toISOString();
179	      return { month: format(d, "MMM"), users: p.filter(u => u.created_at && u.created_at >= s && u.created_at <= e).length };
180	    });
181	
182	    // Plan breakdown
183	    const planChart = [
184	      { plan: "Free",       count: free, pct: p.length ? Math.round((free / p.length) * 100) : 0 },
185	      { plan: "Pro",        count: pro,  pct: p.length ? Math.round((pro  / p.length) * 100) : 0 },
186	      { plan: "Enterprise", count: ent,  pct: p.length ? Math.round((ent  / p.length) * 100) : 0 },
187	    ];
188	
189	    setData({ total: p.length, free, pro, enterprise: ent, invoices: inv ?? 0, contracts: con ?? 0, mrr, arr, userTrend, mrrTrend, mrrChart, userChart, planChart, recent: p.slice(0, 6) });
190	  };
191	
192	  if (!data) return <Spin />;
193	
194	  const { total, pro, enterprise, free, invoices, contracts, mrr, arr, userTrend, mrrTrend, mrrChart, userChart, planChart, recent } = data;
195	
196	  return (
197	    <div className="p-4 md:p-6 lg:p-8 space-y-6 max-w-7xl mx-auto w-full">
198	
199	      {/* ── Top Stat Cards ── */}
200	      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
201	        <StatCard
202	          label="Total Users" value={fmt(total)} sub={`${free} free · ${pro} pro · ${enterprise} ent`}
203	          trend={userTrend} icon={Users} accent="bg-blue-500" onClick={() => onNavigate("users")}
204	        />
205	        <StatCard
206	          label="MRR" value={KES(mrr)} sub="Monthly recurring revenue"
207	          trend={mrrTrend} icon={CreditCard} accent="bg-bronze" onClick={() => onNavigate("billing")}
208	        />
209	        <StatCard
210	          label="ARR" value={KES(arr)} sub="Projected annual revenue"
211	          icon={TrendingUp} accent="bg-emerald-500" onClick={() => onNavigate("billing")}
212	        />
213	        <StatCard
214	          label="Documents" value={fmt(invoices + contracts)} sub={`${invoices} invoices · ${contracts} contracts`}
215	          icon={FileText} accent="bg-violet-500" onClick={() => onNavigate("documents")}
216	        />
217	      </div>
218	
219	      {/* ── Charts Row ── */}
220	      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
221	
222	        {/* MRR Growth */}
223	        <div className="bg-[#111111] border border-white/[0.06] rounded-2xl p-5">
224	          <div className="flex items-start justify-between mb-1">
225	            <div>
226	              <p className="text-xs text-white/40 uppercase tracking-wider font-semibold mb-1">MRR Growth</p>
227	              <p className="text-2xl font-bold text-white tabular-nums">{KES(mrr)}</p>
228	            </div>
229	            <div className="flex items-center gap-1 text-xs text-white/30 bg-white/5 px-2 py-1 rounded-lg">
230	              <span>6 months</span>
231	            </div>
232	          </div>
233	          <p className="text-xs text-white/25 mb-5">Cumulative monthly recurring revenue</p>
234	          <ResponsiveContainer width="100%" height={160}>
235	            <AreaChart data={mrrChart} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
236	              <defs>
237	                <linearGradient id="mrrGrad" x1="0" y1="0" x2="0" y2="1">
238	                  <stop offset="0%"   stopColor="#c47d2a" stopOpacity={0.35} />
239	                  <stop offset="100%" stopColor="#c47d2a" stopOpacity={0} />
240	                </linearGradient>
241	              </defs>
242	              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" vertical={false} />
243	              <XAxis dataKey="month" tick={{ fill: "rgba(255,255,255,0.25)", fontSize: 11 }} axisLine={false} tickLine={false} />
244	              <YAxis tick={{ fill: "rgba(255,255,255,0.25)", fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} tickFormatter={v => v >= 1000 ? `${v/1000}K` : String(v)} />
245	              <Tooltip content={<ChartTooltip prefix="KES " />} />
246	              <Area type="monotone" dataKey="mrr" stroke="#c47d2a" strokeWidth={2} fill="url(#mrrGrad)" dot={false} activeDot={{ r: 4, fill: "#c47d2a", strokeWidth: 0 }} />
247	            </AreaChart>
248	          </ResponsiveContainer>
249	        </div>
250	
251	        {/* User Growth */}
252	        <div className="bg-[#111111] border border-white/[0.06] rounded-2xl p-5">
253	          <div className="flex items-start justify-between mb-1">
254	            <div>
255	              <p className="text-xs text-white/40 uppercase tracking-wider font-semibold mb-1">User Growth</p>
256	              <p className="text-2xl font-bold text-white tabular-nums">{fmt(total)} users</p>
257	            </div>
258	            <div className="flex items-center gap-1 text-xs text-white/30 bg-white/5 px-2 py-1 rounded-lg">
259	              <span>6 months</span>
260	            </div>
261	          </div>
262	          <p className="text-xs text-white/25 mb-5">New signups per month</p>
263	          <ResponsiveContainer width="100%" height={160}>
264	            <AreaChart data={userChart} margin={{ top: 4, right: 4, left: -20, bottom: 0 }}>
265	              <defs>
266	                <linearGradient id="userGrad" x1="0" y1="0" x2="0" y2="1">
267	                  <stop offset="0%"   stopColor="#6366f1" stopOpacity={0.35} />
268	                  <stop offset="100%" stopColor="#6366f1" stopOpacity={0} />
269	                </linearGradient>
270	              </defs>
271	              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" vertical={false} />
272	              <XAxis dataKey="month" tick={{ fill: "rgba(255,255,255,0.25)", fontSize: 11 }} axisLine={false} tickLine={false} />
273	              <YAxis tick={{ fill: "rgba(255,255,255,0.25)", fontSize: 11 }} axisLine={false} tickLine={false} allowDecimals={false} />
274	              <Tooltip content={<ChartTooltip />} />
275	              <Area type="monotone" dataKey="users" stroke="#6366f1" strokeWidth={2} fill="url(#userGrad)" dot={false} activeDot={{ r: 4, fill: "#6366f1", strokeWidth: 0 }} />
276	            </AreaChart>
277	          </ResponsiveContainer>
278	        </div>
279	      </div>
280	
281	      {/* ── Plan Breakdown + Recent ── */}
282	      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
283	
284	        {/* Plan breakdown */}
285	        <div className="bg-[#111111] border border-white/[0.06] rounded-2xl p-5">
286	          <p className="text-xs text-white/40 uppercase tracking-wider font-semibold mb-5">Plan Breakdown</p>
287	          <div className="space-y-4">
288	            {[
289	              { label: "Free",       count: free,       pct: total ? Math.round((free / total) * 100) : 0,       color: "bg-white/20", text: "text-white/50" },
290	              { label: "Pro",        count: pro,        pct: total ? Math.round((pro  / total) * 100) : 0,       color: "bg-emerald-500", text: "text-emerald-400" },
291	              { label: "Enterprise", count: enterprise, pct: total ? Math.round((enterprise / total) * 100) : 0, color: "bg-violet-500",  text: "text-violet-400" },
292	            ].map(row => (
293	              <div key={row.label}>
294	                <div className="flex items-center justify-between mb-2">
295	                  <div className="flex items-center gap-2">
296	                    <div className={cn("w-2 h-2 rounded-full flex-shrink-0", row.color)} />
297	                    <span className={cn("text-sm font-medium", row.text)}>{row.label}</span>
298	                  </div>
299	                  <div className="flex items-center gap-3">
300	                    <span className="text-sm font-bold text-white tabular-nums">{row.count}</span>
301	                    <span className="text-xs text-white/30 w-8 text-right tabular-nums">{row.pct}%</span>
302	                  </div>
303	                </div>
304	                <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
305	                  <div
306	                    className={cn("h-full rounded-full transition-all duration-700", row.color)}
307	                    style={{ width: `${row.pct}%` }}
308	                  />
309	                </div>
310	              </div>
311	            ))}
312	          </div>
313	
314	          {/* MRR breakdown by plan */}
315	          <div className="mt-6 pt-5 border-t border-white/5 space-y-2">
316	            <p className="text-xs text-white/40 uppercase tracking-wider font-semibold mb-3">MRR by Plan</p>
317	            {[
318	              { label: "Pro",        value: pro * 1500,        color: "text-emerald-400" },
319	              { label: "Enterprise", value: enterprise * 5000, color: "text-violet-400" },
320	            ].map(r => (
321	              <div key={r.label} className="flex items-center justify-between">
322	                <span className="text-sm text-white/40">{r.label}</span>
323	                <span className={cn("text-sm font-bold tabular-nums", r.color)}>{KES(r.value)}</span>
324	              </div>
325	            ))}
326	            <div className="flex items-center justify-between pt-2 border-t border-white/5">
327	              <span className="text-sm text-white/60 font-medium">Total MRR</span>
328	              <span className="text-sm font-bold text-bronze tabular-nums">{KES(mrr)}</span>
329	            </div>
330	          </div>
331	        </div>
332	
333	        {/* Recent signups */}
334	        <div className="bg-[#111111] border border-white/[0.06] rounded-2xl p-5">
335	          <div className="flex items-center justify-between mb-5">
336	            <p className="text-xs text-white/40 uppercase tracking-wider font-semibold">Recent Signups</p>
337	            <span className="text-xs text-white/20">{format(new Date(), "dd MMM yyyy")}</span>
338	          </div>
339	          <div className="space-y-1">
