                      )}>{tk.status}</span>
                      <span className="text-xs text-muted-foreground">{format(new Date(tk.created_at), "dd MMM yyyy")}</span>
                    </div>
                  </div>

                  {/* User message */}
                  <p className="text-sm text-muted-foreground whitespace-pre-wrap leading-relaxed">{tk.message}</p>

                  {/* Admin reply */}
                  {tk.admin_reply && (
