          </div>

          {/* Maintenance mode */}
          <div className={cn("border rounded-2xl p-5 transition-all", maintenance ? "bg-amber-500/10 border-amber-500/30" : "bg-[#111] border-white/[0.06]")}>
            <div className="flex items-center justify-between gap-4">
