660	const BillingSection = () => {
661	  const [txns, setTxns]         = useState<any[]>([]);
662	  const [profiles, setProfiles] = useState<any[]>([]);
663	  const [tab, setTab]           = useState<"transactions" | "refunds" | "analytics">("transactions");
664	  const [loading, setLoading]   = useState(true);
665	
666	  useEffect(() => { load(); }, []);
667	
668	  const load = async () => {
669	    const [{ data: txnData }, { data: profData }] = await Promise.all([
670	      supabase
671	        .from("payment_transactions")
672	        .select(`
673	          *,
674	          escrow:escrow_id (
675	            brand:profiles!escrow_payments_brand_id_fkey ( display_name, handle, avatar_url ),
676	            creator:profiles!escrow_payments_creator_id_fkey ( display_name, handle, avatar_url )
677	          )
678	        `)
679	        .order("created_at", { ascending: false })
680	        .limit(150),
681	      supabase
682	        .from("profiles")
683	        .select("id, subscription_plan, subscription_expires_at, created_at"),
684	    ]);
685	    setTxns(txnData ?? []);
686	    setProfiles(profData ?? []);
687	    setLoading(false);
688	  };
689	
690	  const markRefunded = async (id: string) => {
691	    if (!confirm("Mark this transaction as refunded? This updates the status in your records.")) return;
692	    const { error } = await supabase.from("payment_transactions").update({ status: "refunded" }).eq("id", id);
693	    if (error) { toast.error(error.message); return; }
694	    toast.success("Marked as refunded");
695	    load();
696	  };
697	
698	  const total        = txns.reduce((s, t) => s + (t.amount ?? 0), 0);
699	  const completed    = txns.filter(t => t.status === "completed" || t.status === "success").length;
700	  const failed       = txns.filter(t => t.status === "failed").length;
701	  const refunded     = txns.filter(t => t.status === "refunded").length;
702	  const refundable   = txns.filter(t => ["failed", "cancelled"].includes(t.status));
703	  const refundedList = txns.filter(t => t.status === "refunded");
704	
705	  // ── Analytics ──
706	  const now              = new Date();
707	  const nowIso           = now.toISOString();
708	  const successTxns      = txns.filter(t => t.status === "completed" || t.status === "success");
709	  const successRevenue   = successTxns.reduce((s, t) => s + (t.amount ?? 0), 0);
710	  const totalUsers       = profiles.length;
711	  const paidUsers        = profiles.filter(p => p.subscription_plan === "pro" || p.subscription_plan === "enterprise").length;
712	  const conversionRate   = totalUsers > 0 ? ((paidUsers / totalUsers) * 100).toFixed(1) : "0";
713	  const arpu             = totalUsers > 0 ? Math.round(successRevenue / totalUsers) : 0;
714	  const avgTxn           = completed > 0  ? Math.round(successRevenue / completed)  : 0;
715	  // Churned: was paying (has an expiry) but now free/null and expiry is in the past
716	  const churned = profiles.filter(p =>
717	    (!p.subscription_plan || p.subscription_plan === "free") &&
718	    p.subscription_expires_at && p.subscription_expires_at < nowIso
719	  ).length;
720	  // At risk: still paid but expiry within 7 days
